var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"허억……!","JPN":"はあっ……！","ENG":"*Gasp...!*","TWN":"呃呃……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"헉……!","JPN":"はっ……！","ENG":"*Gasp...!*","TWN":"呃……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"허억……! 헉……!","JPN":"はぁ……！　はぁ……！","ENG":"*Huff…!* *Huff…!* *Huff…!*","TWN":"呃呃……！呃……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아……? 레아야, 괜찮니……?","JPN":"レア……？　レア、大丈夫……？","ENG":"Leah...? Leah, are you alright...?","TWN":"蕾亞……？蕾亞？你沒事吧……？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨! 정신 차리고 어서 일어나요!","JPN":"レヴナントさん！　しっかりして、早く起きてください！","ENG":"Revenant! Pull yourself together! Stand up!","TWN":"亡靈小姐！你振作一點，快醒醒！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사방에 침식체들이라고요! 멍하니 있다간 죽어요!","JPN":"周りが侵食体でいっぱいですよ！　ぼっとしていると死にます！","ENG":"There are Corrupted Objects everywhere! If you keep spacing out like that, you’ll die!","TWN":"現在周圍都是侵蝕體！昏倒的話會死掉的！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마…….","JPN":"お母さん……","ENG":"Mom...","TWN":"媽……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우리 엄마…… 만……. 데리고…….","JPN":"お母さん……だけ……連れて……","ENG":"Take... Mom... And...","TWN":"帶……帶我……媽……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"수훈자는 손이 네 개인 줄 알아요?! 제가 휠체어 밀 동안 지켜 줄 사람은 있어야죠!","JPN":"受勲者は手が四つあるとでも思ってるんですか！？　車椅子を押す間に援護する人が必要でしょ！","ENG":"You think a war hero has four hands or what?! I need someone to cover me while I push this wheelchair!","TWN":"你以為授勳者有四隻手嗎？在我推輪椅的時候，總得有人掩護我吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그렇다고 하는군요. 제법 귀여운 아이인데 앙칼진 구석이 있네요.","JPN":"だそうです。結構かわいいのにツンツンしたところがありますね。","ENG":"Ah, so that’s what you meant. She’s quite a cute child, but has a bit of an edge.","TWN":"原來是這樣，長得可愛可愛的，也是有脾氣的呢。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……가 줘.","JPN":"……行って。","ENG":"...Go.","TWN":"……走。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"넌…… 마에스트로? 여긴 어디지?","JPN":"君は……マエストロ？　ここはどこ？","ENG":"Are you... Maestra? Where am I?","TWN":"你是……指揮家？這裡是哪裡？"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"어디도 아닙니다. 눈을 감고 상상하면 떠오르는 무질서한 형태에 색을 입힌 정도죠.","JPN":"どこでもありません。目を閉じて想像すれば浮かび上がる、無秩序な形に色をつけただけです。","ENG":"Nowhere. It is nothing more than the chaotic void you see when you close your eyes, only with a few more colors.","TWN":"哪裡也不是，你閉上眼睛試著想像一下，就像是替浮現的失序狀態上色的感覺。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저</color>는 지금 갑작스럽게 나타난 짙은 역병의 기운에 몸을 가누지 못하는 상태입니다.","JPN":"<color=#ffd34c>私</color>は今、突然現れた深い疫病の気配で体を動かせない状態です。","ENG":"<color=#ffd34c>I</color> cannot handle the plague that has suddenly appeared in my present form.","TWN":"<color=#ffd34c>我</color>現在因為突然出現的瘟疫，導致身體不受控。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"고통이 지나친 나머지, 주마등을 본다고 하면 이해가 되실까요.","JPN":"痛みのあまり、走馬灯を見ると言ったらわかるでしょうか。","ENG":"The pain is too much for me to bear, so my life goes through my mind like a flash.","TWN":"就像是痛到一定程度後，眼前會出現跑馬燈，這樣可以理解嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러니까…… 지금 나 혼자 거울에 대고 말을 하고 있단 뜻이야?","JPN":"だから……今私が一人で鏡に向かって話しているってこと？","ENG":"Do you mean... It’s like I’m talking to myself in the mirror right now?","TWN":"意思是我現在……是在跟鏡子裡的自己對話嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"부연할 필요가 없어서 기쁘군요. 그렇습니다.","JPN":"すぐにわかってもらえて嬉しいです。そのとおりですよ。","ENG":"Correct. I am glad I do not need to elaborate further.","TWN":"沒錯，真開心不用再多做解釋。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"미안하지만 나는 너 따위와 일심동체가 되고 싶었던 적 따위 없어.","JPN":"悪いけど、私は君なんかと一心同体になりたかったことなんてない。","ENG":"I’m sorry but... I’ve never wanted to be one with you.","TWN":"不好意思，我從來沒有想和你融為一體過。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저 역시 아쉽습니다. 온전한 눈으로 담은 세상은 각별하니까요.","JPN":"私も残念だと思っております。完全な目で見つめる世界は格別ですから。","ENG":"That is indeed quite regrettable, for the world is so beautiful to see with eyes.","TWN":"真是遺憾，健全的眼睛看到的世界是很特別的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"돌이켜 보면 이런 과정을 수없이 거쳤겠지요.","JPN":"振り返ってみれば、こういう過程を数知れず繰り返したことでしょう。","ENG":"In retrospect, I must have been through this very process a countless number of times.","TWN":"回想起來，這種過程應該經歷過無數次吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그 아이에게 연구의 진상을 들킨 건…… 아득한 옛날에 있었던 일이니 말입니다.","JPN":"あの子に研究の真相を知らされたのは……遠い昔の事でしたから。","ENG":"The truth of this research was discovered by that child... So, so very long ago.","TWN":"被那孩子發現研究的真相……是好久以前的事。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그림자라면 침식체일 텐데……. 묘하게 온화하네.","JPN":"シャドウといえば侵食体のはずなのに……妙に穏やかだね。","ENG":"If you’re a Shadow, you must be a Corrupted Object... But you are strangely gentle.","TWN":"暗影應該就是侵蝕體吧……你怎麼感覺很溫和？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저와 적대하는 이들은 <color=#ffd34c>저</color> 자신이 아니라 인간들이랍니다.","JPN":"私と敵対する者は<color=#ffd34c>私</color>自身ではなく人間なのです。","ENG":"It is not <color=#ffd34c>I</color> who is against me, it is the humans.","TWN":"和我敵對的人，不是<color=#ffd34c>我</color>自己，而是人類。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"혹은 역병의 기운에 사로잡히지 않을 수 있다면 현실세계에서도 이러하겠죠. 불가능한 조건입니다만.","JPN":"疫病の気に囚われずにいられるのなら、現実世界でも穏やかにいられたでしょう。不可能な条件ですが。","ENG":"If the plague won't affect me, I suppose that I will be like this in Normalside as well. A rather impossible condition.","TWN":"若是可以不身陷瘟疫之中，或許在現實世界也可以這麼溫和，無奈事與願違。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래서…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이런 심령체험이 무슨 의미가 있지?","JPN":"こんな心霊体験に何の意味があるの？","ENG":"What’s the point of this psychic experience?","TWN":"這種心靈體驗有什麼意義嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"자아 성찰이라면 이번 기회에 충분히 했어.","JPN":"自分を振り返ることなら今回の件で十分にしたよ。","ENG":"I’m kind of done with this thorough introspection.","TWN":"是要自我省察嗎？那趁這次機會還不夠嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저 역병의 기운은 이 나라에 퍼져 있던 것을 한데 모아 둔 결과입니다.","JPN":"あの疫病の気はこの国に散らばっていたものを一か所に集めたものです。","ENG":"That dense plague was a result of gathering together all the plague that had spread in this country.","TWN":"瘟疫在這個國家擴散開來，是聚集起來的結果。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저대로 내버려 두면 대균열에 비할 바는 아니지만, 그에 준하는 피해를 야기하겠죠.","JPN":"あのまま放置しておけば大亀裂までとはいかなくても、それに準じる程度の被害を招くでしょう。","ENG":"If left alone, while it isn’t quite comparable to the Grand Dimension Crevice, it may cause damage on the similar scale.","TWN":"再這樣下去，雖然不至於像大峽谷那樣，但會造成類似程度的傷害。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……만약에 사라진다면?","JPN":"……もし消えたら？","ENG":"...And if it disappears?","TWN":"……那消失的話會怎麼樣？"},"stage":{"bg":"ROOM","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"당분간 이 나라에서 침식체를 두려워할 일이 줄어들겠죠.","JPN":"この国ではしばらく侵食体に怯える心配が減るでしょう。","ENG":"For a time, there will be no fear of Corrupted Objects in this country.","TWN":"當然就是這個國家可以暫時減少擔憂侵蝕體的次數。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그 짧은 시간 동안 번영을 추구할 작정이겠지만, 과격한 방법이라는 감상은 지울 수가 없군요.","JPN":"その短い間に繁栄させるつもりでしょうが、過激な方法であるという感は拭えませんね。","ENG":"The intent is to bring about prosperity in that short period of time, but it cannot be denied that it is a rather radical method.","TWN":"雖然我打算在短時間內繁衍，但這個方法似乎太激進。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 침식파가 자연스럽게 사라진다는 얘기는 들은 적 없어.","JPN":"でも侵食波が自然に消えるなんて話、聞いたことない。","ENG":"But I’ve never heard of Corruption rays just disappearing naturally.","TWN":"可是我沒聽說過侵蝕波會自己消失。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"후훗. <color=#ffd34c>제</color>가 있지 않습니까?","JPN":"ふふっ。<color=#ffd34c>私</color>がいるでしょう？","ENG":"Fuu fuu. Am <color=#ffd34c>I</color> not here?","TWN":"呵呵，不是有<color=#ffd34c>我</color>在嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저 정도의 양이라면 제 핵을 재구성할 수 있을 겁니다.","JPN":"あの量なら、私の核を再構成できるはずです。","ENG":"Using that amount of Corruption rays, I shall be able to reconstruct my core.","TWN":"那樣的量足以讓我的核心重組。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……계속 거부한다면 그로니아가 지금보다 더한 지옥이 돼.","JPN":"……断り続けたらグロニアが今よりひどい地獄になる。","ENG":"But if I continue to refuse, Gronia will become a worse hell than it is now.","TWN":"……再拒絕的話，格羅尼亞就會變得比現在更像地獄。"},"stage":{"bg":"TOMB","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"하지만 받아들이면 <color=#ffd34c>제</color> 삶은 다시 만인에게 규탄 받게 되겠죠.","JPN":"でも、受け入れたら<color=#ffd34c>私</color>の人生はまた万人に糾弾されることでしょう。","ENG":"However if accepted, <color=#ffd34c>my</color> life will be condemned by all yet again.","TWN":"接受的話，<color=#ffd34c>我的</color>人生就會再次成為眾矢之的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저</color>는 레아 슈나이더이기 전에, 마에스트로 네퀴티아.","JPN":"<color=#ffd34c>私</color>はレア・シュナイダーである前に、マエストロ・ネキティア。","ENG":"Before <color=#ffd34c>I</color> am Leah Schneider, I am Maestra Nequitia.","TWN":"<color=#ffd34c>我</color>在身為蕾亞·修奈德之前，是指揮家 莉奎蒂亞。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"세상의 안위를 걱정하는 자라면 응당 없애려 들 겁니다.","JPN":"世界の安慰を心配する者ならば、消そうとするに決まっています。","ENG":"Those who truly care about the safety of the world will naturally try to destroy me.","TWN":"擔心世界安危的人，都應當除去。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나는 지금도 침식체들 사이에 있을 엄마가 더 걱정이야.","JPN":"私は今でも侵食体に囲まれているお母さんが心配だよ。","ENG":"I’m still worried about my mother who will be close to the Corrupted Objects.","TWN":"我現在比較擔心的是被侵蝕體包圍的媽媽。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"이제 브레히트 중사도 있군요.","JPN":"ブレヒト軍曹もいますね。","ENG":"Now I have Sergeant Brecht, too.","TWN":"現在布萊希特中士也在。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"역병에 사로잡히면 단원으로 삼으려 하겠어요.","JPN":"役病に囚われたら団員にするおつもりで？","ENG":"If she is corrupted, I shall try to make her into a member.","TWN":"萬一她感染瘟疫，就吸收她為團員吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"카르멘에게는 실망했어. 날 가축 취급이나 하면서 즐기고 있었다니.","JPN":"カルメンにはがっかりしたよ。私を家畜扱いして楽しんでいたなんて。","ENG":"I’m quite disappointed in Carmen. She seemed to enjoy treating me like a pet a little too much.","TWN":"我對卡門好失望，竟然把我當成寵物還很開心。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"단원들의 취미를 장려하는 것도 때로는 도움이 될 때가 있습니다.","JPN":"団員の趣味を奨励することも時には役に立ちますよ。","ENG":"Well. I suppose encouraging some of the members’ hobbies could be helpful.","TWN":"鼓勵團員們有自己的興趣，偶爾也會有好的效果。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"역병의 기운을 취하지 못하고 사망했다면, <color=#ffd34c>저</color>라고 칭하기 혐오스러울 만큼 저등했겠죠.","JPN":"役病の気を受け入れずに死んだら、<color=#ffd34c>私</color>とは言いがたいほど劣等な姿をしていたことでしょう。","ENG":"Had I died before I absorbed the plague’s power, calling the resulting thing <color=#ffd34c>me</color> would be a disgusting insult.","TWN":"萬一沒能沈浸在瘟疫之中便死去的話，根本沒資格稱為<color=#ffd34c>我</color>吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마를 사랑해?","JPN":"お母さんの事、愛してる？","ENG":"Love Mom?","TWN":"愛媽媽嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L40_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"유년기의 기억 탓인지 사랑 운운은 학술적으로 이해해도 실제로 체감할 수는 없더군요.","JPN":"幼年期の記憶のせいか、愛を学術的に理解しても実際に体感することはできませんでした。","ENG":"Perhaps because of my childhood memories, I couldn't really feel love even if I understand it logically.","TWN":"礙於幼年的記憶，愛這種東西，雖然字面上是理解的，卻從未實際體會過。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"안배로 사용할 악보를 완성한 시점에서 그녀에게는 이용 가치가 사라졌으니까요.","JPN":"準備に使う楽譜を完成させた時点で、彼女の利用価値はなくなりましたから。","ENG":"When she completed the score to be used at the ceremony, she had no further value.","TWN":"因為在完成要使用的樂譜後，我對她便已失去利用價值。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"하물며 역병의 기운에 사로잡힌 탓에 온갖 기행으로 피곤하게 굴기까지 했는데…….","JPN":"しかも役病の気に囚われたせいで、あらゆる奇行をしながら面倒をかけさせられたのですが……","ENG":"Moreover, she was obsessed with the plague, and she tired me out with all the bizzarre behavior...","TWN":"況且，或許是瘟疫的關係，她脫序的行為，令人疲憊不已……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……사랑했군요. 우습게도. 의태를 위해 덮어 씌운 기억에 취해.","JPN":"……愛していましたね。滑稽にも。擬態のために上書きさせた記憶に惑わされて。","ENG":"…But I did love her. Funny. Drunk on memories from mimicking.","TWN":"……愛過吧？真可笑，沈浸在因為擬態而覆蓋的記憶裡。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇잖아. 평이한 음악은 따분하니까.","JPN":"そういうものでしょ。単調な曲なんて退屈だから。","ENG":"Simplistic music is boring, isn't it?","TWN":"都說平淡的音樂很枯燥的嘛～"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"네. 음악은 굴곡이 존재해야죠.","JPN":"はい。音楽には変化がなければなりません。","ENG":"Indeed. Music needs to have twists and turns.","TWN":"是的，音樂就是要有高潮迭起。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……눈을 뜨면, 침식체로 죽게 될까?","JPN":"……目覚めたら、侵食体として死ぬのかな？","ENG":"...When I open my eyes, will I die and turn into a Corrupted Object?","TWN":"……我睜開眼睛後就會死於侵蝕體嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그러길 바라고 있죠.","JPN":"そうなることを願っております。","ENG":"I yearn for it.","TWN":"你是這麼希望的吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응. 살면서 나쁜 짓은 차고 넘치게 저지른 것 같은데…….","JPN":"なるほどね。生きながら悪い事は十分やってきたけど……","ENG":"Yeah. I’ve done a lot of bad things in my life...","TWN":"嗯，我活到現在已經壞事幹盡……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"앞으로 그보다 더할까 봐 무서워.","JPN":"これからもっとやるかもしれないから怖いよ。","ENG":"And I’m afraid I’ll do even worse in the future.","TWN":"我怕之後會更勝以往。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨!! 정신 차려요!","JPN":"レヴナントさん！　しっかりしてください！","ENG":"Revenant!! Pull yourself together!","TWN":"亡靈小姐！！你快醒醒！"},"stage":{"bg":"HARMONY_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이미 늦었어, 중사님!","JPN":"もう手遅れよ、軍曹！","ENG":"It’s already too late, Sergeant!","TWN":"她不行了，中士！"},"stage":{"bg":"HARMONY_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르! 코핀 컴퍼니로 연락은 됐어?!","JPN":"イェゴール！　コフィンカンパニーへの連絡はできたの！？","ENG":"Yegor! Were you able to contact Coffin Company?","TWN":"伊高爾！有聯絡上科芬公司嗎？！"},"stage":{"bg":"HARMONY_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>부전대장님! 침식파 시그니처가 관측됩니다! 즉시 그 지역에서 이탈하세요!</color>","JPN":"<color=#ffd34c>副戦隊長！　侵食波シグネチャーが観測されます！　ただちにその地域から離脱してください！</color>","ENG":"<color=#ffd34c>Deputy Commander! A Corruption Ray signature has been detected! Get out of there now!</color>","TWN":"<color=#ffd34c>副戰隊長！監測到侵蝕波標誌！請立刻離開那裡！</color>"},"stage":{"bg":"HARMONY_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아………! 아아……! 아아아아아아아아아아아!!!","JPN":"あ………！　ああ……！　あああああああああああ！！！","ENG":"Ah...! Ahhhh...! Ahhhhhhhhh!!!","TWN":"啊………！啊啊……！啊啊啊啊啊啊啊！！！"},"stage":{"bg":"HARMONY_04_2","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>시그니처 타입은 엘리시움!</color>","JPN":"<color=#ffd34c>シグネチャータイプはエリシウム！</color>","ENG":"<color=#ffd34c>The signature type is Elysium!</color>","TWN":"<color=#ffd34c>標誌類型是愛樂！</color>"},"stage":{"bg":"HARMONY_04_2","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"과연 현실의 공기는 달콤하군요. 특히나 이 공간은 더더욱.","JPN":"やはり、現実世界の空気は甘いですね。特にこの空間はもっと。","ENG":"The air in Normalside is so sweet. Especially this place.","TWN":"現實世界連空氣都是甜的呢，尤其這個空間更是如此。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>개체명 마에스트로 네퀴티아……! 휘하 개체 출몰 감지됩니다!</color>","JPN":"<color=#ffd34c>個体名マエストロ・ネキティア……！　旗下個体の出没が感知されます！</color>","ENG":"<color=#ffd34c>It’s Maestra Nequitia...! Multiple of Nequitia’s subordinates are being detected!</color>","TWN":"<color=#ffd34c>個體名稱是指揮家 莉奎蒂亞……！感應到手下個體出沒！</color>"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>7, 13, 29…… 급속도로 증식 중이에요!</color>","JPN":"<color=#ffd34c>7, 13, 29……急激に増殖中です！</color>","ENG":"<color=#ffd34c>7, 13, 29…… Their numbers are increasing rapidly!</color>","TWN":"<color=#ffd34c>7、13、29……急速增加中！</color>"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"칫…….","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님! 저, 콘트라베이스를 든 그림자……!","JPN":"副戦隊長！　あの、コントラバスを持ったシャドウ……！","ENG":"Deputy Commander! That, Shadow with the contrabass...!","TWN":"副戰隊長！是那個拿低音提琴的暗影……！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님, 죽음까지 각오한 휘하 단원에게 뭔가 해 주실 말씀은 없으신가요?","JPN":"マエストロ、死をも覚悟した旗下の団員に何かおっしゃることはないでしょうか？","ENG":"Maestra Nequitia, do you have anything to say to your men who are prepared to die for you?","TWN":"指揮家，對於願意為你犧牲性命的團員，你沒有什麼話要說嗎？"},"stage":{"bg":"HARMONY_05_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 칭찬은 내가 받아야지. 이제 인간을 돌보는 방법도 터득했는걸.","JPN":"ふふっ。褒めてもらうのは私の方でしょう。もう人間の世話をする方法も身につけたからね。","ENG":"Ha. I deserve all the praise. I did such a great job raising the humans.","TWN":"呵呵，應該要誇獎我才對吧！我可是領會到豢養人類的方法欸！"},"stage":{"bg":"HARMONY_05_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"단원들의 공과에 대한 논의는 최고 단원들이 전부 집결한 다음에 하겠습니다.","JPN":"団員の功罪に対する論議は首席奏者が全員集まった時にさせていただきます。","ENG":"We will discuss the merits of each member after all of our elites arrive.","TWN":"一切的功過，待所有團員到齊後再說吧。"},"stage":{"bg":"HARMONY_05_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"예하께서는 어디로 가셨나요?","JPN":"猊下はどちらですか？","ENG":"Now, where did Eminence go?","TWN":"主教現在在哪裡？"},"stage":{"bg":"HARMONY_05_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄요. 빈사 상태로 꼴사납게 꽁지를 감췄다고 할까요.","JPN":"さあ。瀕死の状態で無様に逃げたってところでしょうか。","ENG":"Well. She tucked her tail and run away rather disgracefully. She was near death.","TWN":"不知道，她去掉大半條命後就當起縮頭烏龜。"},"stage":{"bg":"HARMONY_05_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우후후. 예하께서도 한동안 휴식을 취하셔야 할까. 나한테 부탁하시면 잘 돌봐 드릴 텐데.","JPN":"うふふ。猊下もしばらくお休みをとらないといけないのかしらね。私に頼めば精神誠意お世話するのに。","ENG":"Fuu fuu. Maybe Eminence should take some time off, too. I could take care of her if she wants.","TWN":"呵呵呵，主教也要暫時休息一下嗎？怎麼不跟我說呢？我可以好好照顧她的說。"},"stage":{"bg":"HARMONY_05_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"메이즈 전대, 기억하고 있습니다.","JPN":"メイズ戦隊、覚えております。","ENG":"Maze Division, I remember you.","TWN":"梅茲戰隊，我記得你們。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"과거에나 이번에나 여러분께는 매번 신세를 지는군요.","JPN":"昔も今も、皆さんには毎回お世話になりますね。","ENG":"I owe much to you, both in the past and present.","TWN":"無論是過去或是現在，都很麻煩你們呢。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로……!","JPN":"マエストロ……！","ENG":"Maestra...!","TWN":"指揮家……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"후훗. 그 증오로 가득찬 목소리……. 관리국에 복종한 실패작인가요.","JPN":"ふふっ。憎しみに満ちたあの声……管理局に服従した失敗作ですか。","ENG":"Fuu fuu. That voice so filled with hate... Is it the Administration’s obedient little failed product?","TWN":"呵呵，那刺耳的聲音……是效忠管理局的失敗品嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"저를 지켜 주다니 기특하군요. 보답으로 멋진 연주를 선물해 드리죠.","JPN":"私を守ってくれるとは殊勝ですね。お礼として素晴らしい演奏をお贈りいたしましょう。","ENG":"My thanks for protecting me. In return, I shall give you an incredible performance.","TWN":"沒想到你竟然會保護我，我就送你一場精彩的演奏作為回報吧。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 내 뒤에 서!!","JPN":"全員、私の後ろに隠れて！！","ENG":"Everyone get behind me!!","TWN":"大家到我後面！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"콜록……! 하아……!","JPN":"ゴホッ……！　はあ……！","ENG":"*Cough...!* *Pant...!*","TWN":"唔呃……！呼呼……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님……?!","JPN":"副戦隊長……！？","ENG":"Deputy Commander...?!","TWN":"副戰隊長……？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"의무병! 구경하지 말고 어서 움직여!","JPN":"衛生兵！　見ていないで早く動け！","ENG":"Medic! Don’t just stand there, move!","TWN":"醫務兵！看什麼看！還不快行動！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"파동을 다루는 능력이라…….","JPN":"波動を操る能力……","ENG":"The ability to handle waves...","TWN":"控制波動的能力嗎……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"실패작답군요. 고작 손짓으로 자아내는 힘에 견주자고 그나마 주어진 가능성마저 허비하다니요.","JPN":"失敗作らしいですね。たかが手振りで出せる力に立ち向かうために、残っていた可能性まで無駄遣いするとは。","ENG":"No wonder you’re a failed product. You put forth so much effort just to have a chance in matching my power that I can so easily create with the flick of a wrist.","TWN":"真不愧是失敗品，不惜毀掉自己也要誓死抵抗嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"실패작 소리……! 작작해……!","JPN":"失敗作と呼ぶの……！　言い加減にして……！","ENG":"Saying failed product over and over...! Enough...!","TWN":"不准……！再叫我……失敗品！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그 상태로 싸우려 하신다니, 기개만은 칭찬해 드리죠.","JPN":"その状態で戦おうとするとは、気概だけは褒めてさしあげましょう。","ENG":"Your spirit is quite commendable, attempting to fight in such a state.","TWN":"你這副模樣還想打下去嗎？真是勇氣可嘉呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"허나…… 음?","JPN":"しかし……うむ？","ENG":"But... Huh?","TWN":"不過……嗯？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……본색을 드러냈는가. 마에스트로.","JPN":"……本性を現したか。マエストロ。","ENG":"...Your true colors have been revealed. Maestra.","TWN":"……你終於露出真面目了嗎，指揮家？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이런, 예하께서도 납셨군요.","JPN":"おや、猊下もいらしたのですね。","ENG":"Oh my, even Eminence has appeared.","TWN":"哎呀，主教也來了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"단원들에게 듣기로는 부상이 심하시다 들었습니다만.","JPN":"団員の話では、ひどいケガをされたそうですが。","ENG":"I heard from other members that you sustained a serious injury.","TWN":"不過我聽團員們說，主教好像傷得很重呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 염려 따위 독사의 혓바닥이 자아내는 불경일 따름일지니.","JPN":"貴様の気遣いなど、毒蛇の舌が紡ぐ不敬に過ぎない。","ENG":"Your concern is nothing more than deceitful profanity. Serpent.","TWN":"你的擔心聽起來就像是毒蛇的舌頭發出的毒液。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너에게 안식이 허락될지, 확인해 주리라.","JPN":"貴様に安息が許されるか、ここで確かめよう。","ENG":"I will check to see if rest is to be granted to you.","TWN":"我們就來確認一下，你有沒有資格進入安息吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};